  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\nenum Role {\n  MASTER\n  ADMIN\n  DOCTOR\n  ASSISTANT\n  EMPLOYEE\n}\n\nenum Gender {\n  MALE\n  FEMALE\n  OTHER\n}\n\nenum AppointmentStatus {\n  SCHEDULED\n  CONFIRMED\n  ARRIVED\n  IN_PROGRESS\n  COMPLETED\n  CANCELLED\n  NO_SHOW\n}\n\nenum BillStatus {\n  DRAFT\n  UNPAID\n  PAID\n  CANCELLED\n}\n\nenum BillItemKind {\n  SERVICE\n  ITEM\n  MATERIAL\n  OTHER\n}\n\n// ── People / employees (admin, doctor, assistant, employee) ──\nmodel User {\n  id           Int      @id @default(autoincrement())\n  code         String   @unique\n  name         String\n  email        String   @unique\n  password     String\n  role         Role     @default(EMPLOYEE)\n  phone        String?\n  position     String?\n  specialty    String?\n  licenseNo    String?\n  departmentId Int?\n  active       Boolean  @default(true)\n  createdAt    DateTime @default(now())\n\n  department       Department?   @relation(fields: [departmentId], references: [id])\n  apptsAsDoctor    Appointment[] @relation(\"ApptDoctor\")\n  apptsAsAssistant Appointment[] @relation(\"ApptAssistant\")\n  visits           Visit[]       @relation(\"VisitDoctor\")\n}\n\n// ── Master data ──\nmodel Department {\n  id        Int      @id @default(autoincrement())\n  name      String\n  note      String?\n  active    Boolean  @default(true)\n  createdAt DateTime @default(now())\n\n  users        User[]\n  services     Service[]\n  appointments Appointment[]\n}\n\nmodel Unit {\n  id        Int        @id @default(autoincrement())\n  name      String     @unique\n  items     Item[]\n  materials Material[]\n}\n\nmodel ItemCategory {\n  id    Int    @id @default(autoincrement())\n  name  String @unique\n  items Item[]\n}\n\nmodel PaymentMethod {\n  id    Int    @id @default(autoincrement())\n  name  String @unique\n  bills Bill[]\n}\n\nmodel Room {\n  id           Int           @id @default(autoincrement())\n  name         String\n  note         String?\n  active       Boolean       @default(true)\n  createdAt    DateTime      @default(now())\n  appointments Appointment[]\n}\n\n// รายการบริการ/ค่ารักษา (service master)\nmodel Service {\n  id           Int      @id @default(autoincrement())\n  code         String   @unique\n  name         String\n  price        Float    @default(0)\n  departmentId Int?\n  active       Boolean  @default(true)\n  createdAt    DateTime @default(now())\n\n  department   Department?   @relation(fields: [departmentId], references: [id])\n  appointments Appointment[]\n}\n\n// ── Inventory ──\nmodel Item {\n  id         Int      @id @default(autoincrement())\n  code       String   @unique\n  name       String\n  categoryId Int?\n  unitId     Int?\n  price      Float    @default(0)\n  cost       Float    @default(0)\n  stockQty   Int      @default(0)\n  active     Boolean  @default(true)\n  createdAt  DateTime @default(now())\n\n  category ItemCategory? @relation(fields: [categoryId], references: [id])\n  unit     Unit?         @relation(fields: [unitId], references: [id])\n}\n\nmodel Material {\n  id           Int      @id @default(autoincrement())\n  code         String   @unique\n  name         String\n  unitId       Int?\n  cost         Float    @default(0)\n  stockQty     Int      @default(0)\n  reorderLevel Int?\n  active       Boolean  @default(true)\n  createdAt    DateTime @default(now())\n\n  unit Unit? @relation(fields: [unitId], references: [id])\n}\n\n// ── Patients ──\nmodel Patient {\n  id                Int       @id @default(autoincrement())\n  hn                String    @unique\n  title             String?\n  name              String\n  nationalId        String?\n  photo             String?   @db.Text\n  gender            Gender?\n  birthdate         DateTime?\n  nationality       String?\n  religion          String?\n  maritalStatus     String?\n  occupation        String?\n  phone             String?\n  email             String?\n  address           String?\n  bloodType         String?\n  weight            Float?\n  height            Float?\n  insurance         String?\n  allergies         String?\n  chronic           String?\n  emergencyName     String?\n  emergencyPhone    String?\n  emergencyRelation String?\n  note              String?\n  createdAt         DateTime  @default(now())\n\n  appointments Appointment[]\n  visits       Visit[]\n  bills        Bill[]\n}\n\n// ── Appointment schedule ──\nmodel Appointment {\n  id           Int               @id @default(autoincrement())\n  patientId    Int\n  doctorId     Int?\n  assistantId  Int?\n  departmentId Int?\n  serviceId    Int?\n  roomId       Int?\n  scheduledAt  DateTime\n  endAt        DateTime?\n  status       AppointmentStatus @default(SCHEDULED)\n  note         String?\n  createdAt    DateTime          @default(now())\n\n  patient    Patient     @relation(fields: [patientId], references: [id])\n  doctor     User?       @relation(\"ApptDoctor\", fields: [doctorId], references: [id])\n  assistant  User?       @relation(\"ApptAssistant\", fields: [assistantId], references: [id])\n  department Department? @relation(fields: [departmentId], references: [id])\n  service    Service?    @relation(fields: [serviceId], references: [id])\n  room       Room?       @relation(fields: [roomId], references: [id])\n  visit      Visit?\n}\n\n// ── Patient report / clinical encounter ──\nmodel Visit {\n  id             Int      @id @default(autoincrement())\n  patientId      Int\n  appointmentId  Int?     @unique\n  doctorId       Int?\n  visitDate      DateTime @default(now())\n  chiefComplaint String?\n  diagnosis      String?\n  treatment      String?\n  note           String?\n  createdAt      DateTime @default(now())\n\n  patient      Patient       @relation(fields: [patientId], references: [id])\n  appointment  Appointment?  @relation(fields: [appointmentId], references: [id])\n  doctor       User?         @relation(\"VisitDoctor\", fields: [doctorId], references: [id])\n  bill         Bill?\n  voiceRecords VoiceRecord[]\n}\n\n// ── บันทึกเสียงในแผนการรักษา (อัดเสียง + ซับ) ──\nmodel VoiceRecord {\n  id          Int      @id @default(autoincrement())\n  visitId     Int\n  audioFile   String? // ชื่อไฟล์เสียงบนดิสก์ (uploads/voice/*.webm)\n  transcript  String?  @db.Text // ซับ/ข้อความจากเสียง\n  durationSec Int      @default(0)\n  createdAt   DateTime @default(now())\n\n  visit Visit @relation(fields: [visitId], references: [id], onDelete: Cascade)\n}\n\n// ── Billing ──\nmodel Bill {\n  id              Int        @id @default(autoincrement())\n  billNo          String     @unique\n  patientId       Int\n  visitId         Int?       @unique\n  date            DateTime   @default(now())\n  discount        Float      @default(0)\n  subtotal        Float      @default(0)\n  total           Float      @default(0)\n  status          BillStatus @default(UNPAID)\n  paymentMethodId Int?\n  paidAt          DateTime?\n  note            String?\n  createdAt       DateTime   @default(now())\n\n  patient       Patient        @relation(fields: [patientId], references: [id])\n  visit         Visit?         @relation(fields: [visitId], references: [id])\n  paymentMethod PaymentMethod? @relation(fields: [paymentMethodId], references: [id])\n  items         BillItem[]\n}\n\nmodel BillItem {\n  id          Int          @id @default(autoincrement())\n  billId      Int\n  kind        BillItemKind @default(OTHER)\n  refId       Int?\n  description String\n  qty         Int          @default(1)\n  unitPrice   Float        @default(0)\n  amount      Float        @default(0)\n\n  bill Bill @relation(fields: [billId], references: [id], onDelete: Cascade)\n}\n",
